import React, { useEffect, useRef, useState } from "react";
import { useTranslation } from "react-i18next";
import { useDispatch } from "react-redux";
import { mobileLayoutFrom } from "../../constants/mobileLayoutFrom";
import useHover from "../../hooks/useHover";
import { useTypedSelector } from "../../hooks/useTypedSelector";
import { tbResetAllAction, tbAddSlotAction, tbRemoveSlotAction, tbSetSlotsAction, SlotInterface} from "../../store/reducers/tb-reducer";
import { ArrowLeftSVG } from "../svg/ArrowLeft";
import { ArrowRightSVG } from "../svg/ArrowRight";
import { XMarkSVG } from "../svg/XMark";
import { Toggle } from "../toggle/Toggle";
import { TbSlot } from "./tb-slot/TbSlot";
import "./TbSlots.css";

type LayoutType = "grid" | "line";

// Define preset data structure
interface Preset {
  id: string;
  name: string;
  data: {
    slots: SlotInterface[];
    teamName?: string;
    teamDescription?: string;
  };
}

export const TbSlots = () =>{
    const {slots} = useTypedSelector(store => store.tbReducer);
    const {t} = useTranslation();
    const dispatch = useDispatch();
    const containerRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    
    // Presets state
    const [presets, setPresets] = useState<Preset[]>(() => {
      const savedPresets = localStorage.getItem('tb-presets');
      return savedPresets ? JSON.parse(savedPresets) : [];
    });
    const [showPresets, setShowPresets] = useState(false);
    const [editingPresetId, setEditingPresetId] = useState<string | null>(null);
    
    const getStoredLayout = () => {
        const storedLayout = localStorage.getItem("tb-layout") || "line";
        return storedLayout as LayoutType;
    }
    
    const [layout , setLayout] = useState<LayoutType>(getStoredLayout());
    const [animatedClass , setAnimatedClass] = useState(getStoredLayout() === "line" ? "tb-slots-container--flex" : "tb-slots-container--grid");
    const [timeoutId, setTimeoutId] = useState<null|NodeJS.Timeout>(null);
    const isHovering = useHover(containerRef);
    const [teamName, setTeamName] = useState(() => {
        const savedName = localStorage.getItem('tb-team-name') || '';
        return savedName;
    });
    const [teamDescription, setTeamDescription] = useState(() => {
        const savedDesc = localStorage.getItem('tb-team-description') || '';
        return savedDesc;
    });
    const [showInputs, setShowInputs] = useState(true);

    useEffect(() => {
        localStorage.setItem('tb-team-name', teamName);
    }, [teamName]);
    
    useEffect(() => {
        localStorage.setItem('tb-team-description', teamDescription);
    }, [teamDescription]);
    
    // Save presets to localStorage when they change
    useEffect(() => {
      localStorage.setItem('tb-presets', JSON.stringify(presets));
    }, [presets]);

    // Function to handle download
    const handleDownload = () => {
        const data = {
            slots: slots,
            layout: layout,
            teamName: teamName,
            teamDescription: teamDescription,
            version: "1.0"
        };
        
        const blob = new Blob([JSON.stringify(data, null, 2)], {type: "application/json"});
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `timbelder-data-${new Date().toISOString().slice(0,10)}.json`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };
    
    // Function to handle file upload
    const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (!file) return;
        
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const content = e.target?.result as string;
                const data = JSON.parse(content);
                
                // Validate the data structure
                if (data && Array.isArray(data.slots)) {
                    tbSetSlotsAction(dispatch, {slots: data.slots});

                    if (data.teamName) setTeamName(data.teamName);
                    if (data.teamDescription) setTeamDescription(data.teamDescription);
                    
                    // Optional: restore layout if present in the file
                    if (data.layout && ["grid", "line"].includes(data.layout)) {
                        setLayout(data.layout);
                        localStorage.setItem("tb-layout", data.layout);
                    }
                    
                    alert("Data imported successfully!");
                } else {
                    alert("Invalid file format. Please upload a valid Timbelder data file.");
                }
            } catch (error) {
                console.error("Error parsing file:", error);
                alert("Error parsing file. Please check the file format.");
            }
        };
        reader.readAsText(file);
        
        // Reset the input to allow selecting the same file again
        if (fileInputRef.current) {
            fileInputRef.current.value = "";
        }
    };
    
    const handleScrollLeft = () => {
        if (containerRef && containerRef.current) {
            const currentScroll = containerRef.current.scrollLeft;
            const targetScroll = currentScroll - 280;
            containerRef.current.scrollTo({
              left: targetScroll,
              behavior: "smooth", 
            });
          }
    };
    
    const handleScrollRight = () => {
        if (containerRef && containerRef.current) {
            const currentScroll = containerRef.current.scrollLeft;
            const targetScroll = currentScroll + 280;
            containerRef.current.scrollTo({
              left: targetScroll,
              behavior: "smooth", 
            });
          }
    };
    
    const handleLayoutChange = () => {
        if (timeoutId) {
            clearTimeout(timeoutId);
        }
        setAnimatedClass(`${animatedClass} hidden`);
        const newTimeoutId = setTimeout(() => {
            if(layout === "grid") setAnimatedClass("tb-slots-container--flex"); 
            else setAnimatedClass("tb-slots-container--grid"); 
        }, 500);

        setTimeoutId(newTimeoutId);

        const newLayout = layout === "grid" ? "line" : "grid";
        setLayout(newLayout);
        localStorage.setItem("tb-layout",newLayout)
    } 
    
    const handleSlotAdd = () => {
        if(slots.length < 12) tbAddSlotAction(dispatch);
    }
    
    const handleSlotRemove = () =>{
        if(slots.length > 5) tbRemoveSlotAction(dispatch);
    } 
    
    const handleMouseWheel = (e: React.WheelEvent) => {
        const container = containerRef.current;
        if (container) {
            container.scrollLeft += e.deltaY;
        }
    };

    // Save current setup as a preset
    const saveAsPreset = () => {
      const presetName = prompt("Enter preset name:");
      if (!presetName) return;
      
      const newPreset: Preset = {
        id: Date.now().toString(),
        name: presetName,
        data: {
          slots: [...slots],
          teamName,
          teamDescription
        }
      };
      
      setPresets([...presets, newPreset]);
    };
    
    // Update existing preset
    const updatePreset = (id: string) => {
      const presetToUpdate = presets.find(p => p.id === id);
      if (!presetToUpdate) return;
      
      const updatedPreset = {
        ...presetToUpdate,
        data: {
          slots: [...slots],
          teamName,
          teamDescription
        }
      };
      
      setPresets(presets.map(p => p.id === id ? updatedPreset : p));
      setEditingPresetId(null);
    };
    
    // Load a preset
    const loadPreset = (preset: Preset) => {
      if (window.confirm(`Load preset "${preset.name}"?`)) {
        tbSetSlotsAction(dispatch, {slots: preset.data.slots});
        if (preset.data.teamName) setTeamName(preset.data.teamName);
        if (preset.data.teamDescription) setTeamDescription(preset.data.teamDescription);
      }
    };
    
    // Delete a preset
    const deletePreset = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      if (window.confirm("Delete this preset?")) {
        setPresets(presets.filter(p => p.id !== id));
      }
    };

    // Start editing a preset
    const startEditingPreset = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      setEditingPresetId(id);
    };

    // Cancel editing
    const cancelEditingPreset = () => {
      setEditingPresetId(null);
    };

    useEffect(() => {
        if (window.innerWidth <= mobileLayoutFrom || layout === "grid") return;
      
        const mainElements = document.getElementsByTagName('main');
        const currentScrollDepth = window.scrollY;
      
        if (isHovering ) {
          const mainElementsArray = Array.from(mainElements);
          for (const mainElement of mainElementsArray) {
            mainElement.style.position = 'fixed';
            mainElement.dataset.scrollY = mainElement.dataset.scrollY || `${currentScrollDepth}`;
            mainElement.style.top = `-${mainElement.dataset.scrollY}px`;
          }
        } else {
          const mainElementsArray = Array.from(mainElements);
          for (const mainElement of mainElementsArray) {
            mainElement.style.position = 'unset';
            mainElement.style.top = '0';
            const savedScrollY = parseFloat(mainElement.dataset.scrollY || "0") ;
            window.scrollTo(0, savedScrollY);
            mainElement.dataset.scrollY = '';
          }
        }
    }, [isHovering]);

    useEffect(() => {
        const storedSlots = localStorage.getItem("tb-stored-slots");
        if(storedSlots){
            const parsedSlots = JSON.parse(storedSlots) as SlotInterface[];
            if(Array.isArray(parsedSlots)){
                tbSetSlotsAction(dispatch,{slots:parsedSlots});
            }
        }
    }, []);

    return (
        <section className="tb-slots"
        onScroll={(e)=>e.preventDefault()} 
        onWheel={(e)=>{e.preventDefault();e.stopPropagation()}}>
            <div style={{display:"flex",flexDirection:"row", justifyContent:"space-between",alignItems:"center"}}>
                <div className={"tb-slots-collapse-wrapper"} style={{display:"flex", gap:"10px"}}> 
                    <span className="tb-slots-btnSlotText">{t("TbSlots.slotsCount")}</span>
                    <div className="tb-slots-btnSlotCount">
                        <button style={{color:"white"}}onClick={handleSlotRemove}>−</button>
                        <span>{slots.length}</span>
                        <button style={{color:"white"}}onClick={handleSlotAdd}>+</button>
                    </div>
                </div>
                <div style={{display:"flex",flexDirection:"row", gap:"10px"}}>
                    <Toggle positionClass="tb-slots-toggle" click={handleLayoutChange}/>
                    <button className="tb-slots-reset" onClick={()=> tbResetAllAction(dispatch) }><XMarkSVG/> {t("TbSlots.reset")}</button>
                </div>
            </div>
            
            {/* Add the new buttons for download/upload */}
            <div style={{display: "flex", gap: "10px", margin: "10px 0"}}>
                <button className="tb-slots-download" onClick={handleDownload}>
                    {t("TbSlots.download") || "Download Data"}
                </button>
                
                <input
                    type="file"
                    ref={fileInputRef}
                    onChange={handleFileUpload}
                    accept=".json"
                    style={{display: "none"}}
                />
                
                <button 
                    className="tb-slots-upload" 
                    onClick={() => fileInputRef.current?.click()}
                >
                    {t("TbSlots.upload") || "Upload Data"}
                </button>
                
                <button 
                    className="tb-slots-preset" 
                    onClick={() => setShowPresets(!showPresets)}
                >
                    {t("TbSlots.presets") || "Presets"} {showPresets ? '▲' : '▼'}
                </button>
                
                <button 
                    className="tb-slots-save-preset" 
                    onClick={saveAsPreset}
                >
                    {t("TbSlots.savePreset") || "Save as Preset"}
                </button>
                
               
                <button 
                    className="tb-slots-preset" 
                    onClick={() => setShowInputs(!showInputs)}
                >
                    {t("TbSlots.information")} {showInputs ? '▲' : '▼'}
                </button>
            </div>
            
            {/* Presets dropdown */}
            {showPresets && (
              <div className="tb-presets-list">
                {presets.length === 0 ? (
                  <div className="tb-preset-empty">No presets saved</div>
                ) : (
                  presets.map(preset => (
                    <div 
                      key={preset.id} 
                      className="tb-preset-item"
                      onClick={() => editingPresetId !== preset.id && loadPreset(preset)}
                    >
                      {editingPresetId === preset.id ? (
                        <div className="tb-preset-edit-mode">
                          <span>{preset.name}</span>
                          <div className="tb-preset-edit-buttons">
                            <button 
                              className="tb-preset-confirm"
                              onClick={(e) => {
                                e.stopPropagation();
                                updatePreset(preset.id);
                              }}
                            >
                              ✓
                            </button>
                            <button 
                              className="tb-preset-cancel"
                              onClick={(e) => {
                                e.stopPropagation();
                                cancelEditingPreset();
                              }}
                            >
                              ✕
                            </button>
                          </div>
                        </div>
                      ) : (
                        <>
                          <span>{preset.name}</span>
                          <div className="tb-preset-buttons">
                            <button 
                              className="tb-preset-edit"
                              onClick={(e) => startEditingPreset(preset.id, e)}
                            >
                              ✎
                            </button>
                            <button 
                              className="tb-preset-delete"
                              onClick={(e) => deletePreset(preset.id, e)}
                            >
                              🗑
                            </button>
                          </div>
                        </>
                      )}
                    </div>
                  ))
                )}
              </div>
            )}
            
            <button aria-label="slide left" className={`tb-slots-btnLeft ${(animatedClass.includes("hidden") || layout==="grid") ? "hidden": ""}`} onClick={handleScrollLeft}><ArrowLeftSVG/></button>
            <button aria-label="slide right" className={`tb-slots-btnRight ${(animatedClass.includes("hidden") || layout==="grid") ? "hidden": ""}`} onClick={handleScrollRight}><ArrowRightSVG/></button>
            
            <div className={["tb-slots-container", animatedClass, (isHovering && layout==="line") &&  "tb-slots-container--gloving"].join(" ")} 
                 ref={containerRef}
                 onWheel={(e)=>handleMouseWheel(e)}
                >
                    {slots.map((slot,index)=>{
                        return(
                            <TbSlot slot={slot} index={index} key={"id"+index}></TbSlot>
                        )
                    })}
            </div>
            
            <div className="tb-team-info">
                {showInputs && (
                    <>
                        <input
                            type="text"
                            placeholder={t("TbSlots.teamName")}
                            value={teamName}
                            onChange={(e) => setTeamName(e.target.value)}
                            className="tb-team-inputName"
                        />
                        <textarea
                            placeholder={t("TbSlots.teamDescription")}
                            value={teamDescription}
                            onChange={(e) => setTeamDescription(e.target.value)}
                            className="tb-team-inputDiscription"
                        />
                    </>
                )}
            </div>
        </section>
    )
}