import { useQuery, QueryClient } from "react-query";
import { SUPABASE_URL, SUPABASE_ANON_KEY } from "../utils/supabaseClient";
import { egoKeys } from "../constants/egoKeys"; // Твой конфиг для EGO

const CACHE_KEY = 'egos_cache';
const CACHE_TIME = 15 * 60 * 1000; // 35 минут

const getDataFromCache = () => {
  if (typeof window === 'undefined') return null;
  const cachedData = localStorage.getItem(CACHE_KEY);
  if (cachedData) {
    const { data, timestamp } = JSON.parse(cachedData);
    if (Date.now() - timestamp < CACHE_TIME) return data;
  }
  return null;
};

const setDataToCache = (data: any) => {
  localStorage.setItem(CACHE_KEY, JSON.stringify({ data, timestamp: Date.now() }));
};

const useFetchEgosAction = async () => {
  const cached = getDataFromCache();
  if (cached) return cached;

  // Запрос к таблице ego. Используем сортировку по имени, чтобы порядок не прыгал
  const url = `${SUPABASE_URL}/rest/v1/ego?select=*&order=%22nameEN%22.asc&apikey=${SUPABASE_ANON_KEY}`;
  
  const response = await fetch(url);
  if (!response.ok) throw new Error("Ошибка загрузки EGO из Supabase");

  const rawData = await response.json();

  // Применяем твои валидаторы к каждой строке
  const validatedData = rawData.map((row: any) => {
    const item: any = {};
    
    egoKeys.forEach(({ key, validation }) => {
      // Ищем значение в строке, учитывая возможный разный регистр в БД
      const rawValue = row[key] !== undefined ? row[key] : row[key.toLowerCase()];
      
      // Передаем в валидатор. Если в базе null, передаем пустую строку
      const { validatedVal } = validation(rawValue ?? "");
      
      item[key] = validatedVal;
    });

    return item;
  });

  console.log("Validated EGO Data:", validatedData);
  setDataToCache(validatedData);
  return validatedData;
};

export const useFetchEgos = () => {
  return useQuery("ego", useFetchEgosAction, {
    staleTime: CACHE_TIME,
    cacheTime: Infinity,
    refetchOnWindowFocus: false,
    retry: 5,
    onError: (error) => {
      console.error("Error fetching ego from Supabase:", error);
    },
  });
};

export const createQueryClient = () => {
  const queryClient = new QueryClient({
    defaultOptions: {
      queries: {
        staleTime: CACHE_TIME,
        cacheTime: Infinity,
      },
    },
  });

  if (typeof window !== 'undefined') {
    const cachedData = getDataFromCache();
    if (cachedData) {
      queryClient.setQueryData("ego", cachedData);
    }
  }

  return queryClient;
};