import { useQuery, QueryClient } from "react-query";
import { SUPABASE_URL, SUPABASE_ANON_KEY } from "../utils/supabaseClient";

// 1. Константы
const CACHE_KEY = 'statuses_cache';
const CACHE_TIME = 15 * 60 * 1000; // 1 час

// 2. Утилиты кэша
const getDataFromCache = () => {
  if (typeof window === 'undefined') return null;
  const cachedData = localStorage.getItem(CACHE_KEY);
  if (cachedData) {
    const { data, timestamp } = JSON.parse(cachedData);
    if (Date.now() - timestamp < CACHE_TIME) {
      return data;
    }
  }
  return null;
};

const setDataToCache = (data: any) => {
  const cacheData = { data, timestamp: Date.now() };
  localStorage.setItem(CACHE_KEY, JSON.stringify(cacheData));
};

const useFetchStatusesAction = async () => {
  const cached = getDataFromCache();
  if (cached) return cached;

  const sinnerUrl = `${SUPABASE_URL}/rest/v1/sinner_statuses?select=*&apikey=${SUPABASE_ANON_KEY}`;
  const anomalyUrl = `${SUPABASE_URL}/rest/v1/anomaly_statuses?select=*&apikey=${SUPABASE_ANON_KEY}`;

  const [sinnerRes, anomalyRes] = await Promise.all([
    fetch(sinnerUrl),
    fetch(anomalyUrl)
  ]);

  if (!sinnerRes.ok || !anomalyRes.ok) {
    throw new Error("Ошибка при загрузке статусов");
  }

  const rawSinnerData = await sinnerRes.json();
  const rawAnomalyData = await anomalyRes.json();

  const transformData = (data: any[]) => data.map(item => {
    const newItem = { ...item };

    // Защита от undefined: гарантируем, что поля будут хотя бы пустыми строками
    // чтобы поиск .toLowerCase() не падал
    newItem.nameEN = item.nameEN || item.nameen || "";
    newItem.nameRU = item.nameRU || item.nameru || "";
    newItem.descriptionEN = item.descriptionEN || item.descriptionen || "";
    newItem.descriptionRU = item.descriptionRU || item.descriptionru || "";

    // ИСПРАВЛЕНИЕ OWNERS: Разделяем строку по запятой
    if (typeof item.owners === 'string') {
      // split(',') режет строку, а map(s => s.trim()) убирает лишние пробелы
      newItem.owners = item.owners.split(',').map((s: string) => s.trim());
    } else if (!item.owners) {
      newItem.owners = [];
    }

    return newItem;
  });

  const combinedData = [
    ...transformData(rawSinnerData),
    ...transformData(rawAnomalyData)
  ];

  setDataToCache(combinedData);
  return combinedData;
};

// 4. Основной хук
export const useFetchStatuses = () => {
  return useQuery("statuses", useFetchStatusesAction, {
    staleTime: CACHE_TIME,
    cacheTime: Infinity,
    refetchOnWindowFocus: false,
    retry: 8,
    retryDelay: (attempt) =>
      Math.min(attempt > 1 ? 2 ** attempt * 1000 : 1000, 30 * 1000),
    onError: (error) => {
      console.error("Error fetching statuses from Supabase:", error);
    },
  });
};

// 5. QueryClient
export const createQueryClient = () => {
  const queryClient = new QueryClient({
    defaultOptions: {
      queries: {
        staleTime: CACHE_TIME,
        cacheTime: Infinity,
      },
    },
  });

  if (typeof window !== 'undefined') {
    const cachedData = getDataFromCache();
    if (cachedData) {
      queryClient.setQueryData("statuses", cachedData);
    }
  }

  return queryClient;
};