// TestComponent.tsx
import React, { ChangeEvent, useState } from 'react';
// Импортируем только актуальный форматтер
import { SkillCoinDescription } from "../guides/text-formatter/SkillCoinDescription";
import './TestComponent.css';

interface ITestComponentProps {}

export const TestComponent: React.FC<ITestComponentProps> = () => {
  const [description, setDescription] = useState("");

  const handleChange = (e: ChangeEvent<HTMLTextAreaElement>) => {
    setDescription(e.target.value);
  };

  return (
    <>
      {/* Контейнер для ввода текста */}
      <textarea 
        className="descriptionTextarea"
        placeholder="Введите текст с тегами (например, #Burn# или $onhit$)..."
        cols={130} 
        rows={10} 
        onChange={handleChange}
      ></textarea>
      
      {/* Рендерим описание, разделенное символом "|" */}
      {description.split("|").map((desc, index) => {
        return (
          <div 
            key={index} 
            className="descriptionContainer"
          >
            <SkillCoinDescription description={desc} />
          </div>
        );
      })}
    </>
  );
};