import React, { useState, useEffect } from 'react';
import { useQueryClient } from 'react-query';
import { StatusesInterface } from '../../store/reducers/statuses-reducer';
import { IdentityInterface } from '../../store/reducers/ids-reducer';
import { ItemEntity } from '../item-entity/ItemEntity';
import './PickAndBan.css';

export const PickAndBan = () => {
    const queryClient = useQueryClient();
    const statuses = queryClient.getQueryData('statuses') as StatusesInterface[];
    const ids = queryClient.getQueryData('identities') as IdentityInterface[] | null;
    
    const mainStatuses = ['burn', 'bleed', 'tremor', 'rupture', 'poise', 'sinking', 'charge'];
    
    const [bannedStatuses, setBannedStatuses] = useState<string[]>([]);
    const [leftSelectedStatuses, setLeftSelectedStatuses] = useState<string[]>([]);
    const [rightSelectedStatuses, setRightSelectedStatuses] = useState<string[]>([]);
    
    // Автоматическое распределение статусов после бана
    useEffect(() => {
        const available = mainStatuses.filter(status => !bannedStatuses.includes(status));
        
        // Распределяем оставшиеся статусы между колонками
        const left = available.slice(0, Math.ceil(available.length / 2));
        const right = available.slice(Math.ceil(available.length / 2));
        
        setLeftSelectedStatuses(left);
        setRightSelectedStatuses(right);
    }, [bannedStatuses]);
    
    const getIdentitiesWithStatus = (status: string) => {
        if (!ids) return [];
        
        return ids.filter(id => {
            const descriptionCoinEN = id.descriptionCoinEN4 || '';
            const descriptionPassive1EN = id.descriptionPassive1EN || '';
            const descriptionPassive2EN = id.descriptionPassive2EN || '';
            
            const descriptions = [descriptionCoinEN, descriptionPassive1EN, descriptionPassive2EN];
            const statusList = descriptions.join(' ').toLowerCase();
            
            return statusList.includes(status.toLowerCase());
        });
    };
    
    const handleBanStatus = (status: string) => {
        if (bannedStatuses.length >= 3) return;
        setBannedStatuses([...bannedStatuses, status]);
    };
    
    const handleUnbanStatus = (status: string) => {
        setBannedStatuses(bannedStatuses.filter(s => s !== status));
    };
    
    return (
        <div className="pick-and-ban-container">
            <h2>Pick and Ban Statuses</h2>
            
            {/* Блок забаненных статусов */}
            <div className="banned-section">
                <h3>Banned Statuses (Max 3)</h3>
                <div className="status-grid">
                    {bannedStatuses.map(status => (
                        <div key={`banned-${status}`} className="status-item banned" onClick={() => handleUnbanStatus(status)}>
                            {status}
                        </div>
                    ))}
                    {mainStatuses
                        .filter(status => !bannedStatuses.includes(status))
                        .map(status => (
                            <div key={`available-${status}`} className="status-item available" onClick={() => handleBanStatus(status)}>
                                {status}
                            </div>
                        ))}
                </div>
            </div>
            
            {/* Основной блок с выбранными статусами и личностями */}
            {bannedStatuses.length === 3 && (
                <div className="main-section">
                    {/* Левая колонка */}
                    <div className="left-column">
                        {leftSelectedStatuses.map(status => (
                            <div key={`left-${status}`} className="status-column">
                                <div className="status-header selected">
                                    {status}
                                </div>
                                <div className="identities-list">
                                    {getIdentitiesWithStatus(status).map(identity => (
                                        <ItemEntity key={`left-${status}-${identity.imgUrl}`} entity={identity} />
                                    ))}
                                </div>
                            </div>
                        ))}
                    </div>
                    
                    {/* Правая колонка */}
                    <div className="right-column">
                        {rightSelectedStatuses.map(status => (
                            <div key={`right-${status}`} className="status-column">
                                <div className="status-header selected">
                                    {status}
                                </div>
                                <div className="identities-list">
                                    {getIdentitiesWithStatus(status).map(identity => (
                                        <ItemEntity 
                                            key={`right-${status}-${identity.imgUrl}`} 
                                            entity={identity}  
                                        />
                                    ))}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
};