import { useState, KeyboardEvent, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { useAuth } from "./authUtils";
import RegistrationForm from './RegistrationForm';
import { BingoGame } from './BingoGame';
import TournamentGrid from './TournamentGrid';
import { PickAndBan } from './PickAndBan';
import "./TurnamentInfo.css";

export const TurnamentInfo: React.FC = () => {
    const { t } = useTranslation();
    const [activeTab, setActiveTab] = useState('info');
    const [showAuthModal, setShowAuthModal] = useState(false);
    const { isAuthorized, password, setPassword, handleCheckPassword, errorMessage, logout } = useAuth();

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.ctrlKey && e.shiftKey) {
                setShowAuthModal(true);
                e.preventDefault();
            }
        };

        window.addEventListener('keydown', handleKeyDown as any);
        return () => window.removeEventListener('keydown', handleKeyDown as any);
    }, []);

    const handleKeyDown = (e: KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter') {
            handleCheckPassword();
        }
    };

    const renderContent = () => {
        switch (activeTab) {
            case 'info':
                return (
                    <div className="info-sections-container">
                        <div className="info-section">
                            <h3 className="section-title">{t('TurnamentInfo.sections.rules.title')}</h3>
                            <div className="section-divider"></div>
                            <div className="section-content">
                                <p>{t("TurnamentInfo.sections.rules.text1")}</p>
                                <p>{t("TurnamentInfo.sections.rules.text2")}</p>
                                <p>{t("TurnamentInfo.sections.rules.text3")}</p>
                                <p>{t("TurnamentInfo.sections.rules.text4")}</p>
                                <p>{t("TurnamentInfo.sections.rules.text5")}</p>
                                <p><a className="ssilka" href="https://docs.google.com/document/d/1XewtA6CPbOYdqA0FqDa_FYPoYyHmbkiTvwUmrTq8Ufw/edit?tab=t.0" target="_blank" rel="noopener noreferrer">
                                    {t("TurnamentInfo.sections.rules.text7")}</a>
                                </p>
                            </div>
                        </div>
                        
                        <div className="info-section">
                            <h3 className="section-title">{t('TurnamentInfo.sections.tournament.title')}</h3>
                            <div className="section-divider"></div>
                            <div className="section-content">
                                <p>{t("TurnamentInfo.sections.tournament.text1")}</p>
                                <p>{t("TurnamentInfo.sections.tournament.text2")}</p>
                                <p>{t("TurnamentInfo.sections.tournament.text3")}</p>
                                <p>{t("TurnamentInfo.sections.tournament.text4")}</p>
                                <p><a className="ssilka" href="https://www.twitch.tv/gllfun_ru" target="_blank" rel="noopener noreferrer" >{t("TurnamentInfo.sections.tournament.text5")}</a></p>
                            </div>
                        </div>
                        
                        <div className="info-section">
                            <h3 className="section-title">{t('TurnamentInfo.sections.organizer.title')}</h3>
                            <div className="section-divider"></div>
                            <div className="section-content">
                            <p><a className="ssilka" href="https://www.youtube.com/@ilyaKek482" target="_blank" rel="noopener noreferrer">{t("TurnamentInfo.sections.organizer.text1")}</a></p>
                                <p><a className="ssilka" href="https://www.youtube.com/@HC_NR" target="_blank" rel="noopener noreferrer" >{t("TurnamentInfo.sections.organizer.text5")}</a></p>
                            </div>
                        </div>
                    </div>
                );
            case 'registration':
                return <RegistrationForm />;
            case 'schedule':
                return <TournamentGrid />;
            case 'bingo':
                return isAuthorized ? <BingoGame /> : null;
            case 'pickandban':
                return isAuthorized ? <PickAndBan /> : null;
            default:
                return null;
        }
    };

    return (
        <section className="graditude-info">
            <div className="tournament-info">
                <div className="image-container">
                    <img  className="image-container3"
                        src="/images/reklamaimage.png" 
                        alt="Tournament Cup" 
                    />
                </div>
            </div>
            
            <div className="button-container">
                <nav className="button-list">
                    <ul>
                        {['info', 'registration'].map((tab) => (
                            <li key={tab}>
                                <button
                                    onClick={() => setActiveTab(tab)}
                                    className={activeTab === tab ? 'active' : ''}
                                >
                                    {t(`TurnamentInfo.${tab}.header`)}
                                </button>
                                {activeTab === tab && <div className="button-list-line"/>}
                            </li>
                        ))}
                        
                        {isAuthorized && (
                            <>
                                {['bingo', 'pickandban'].map((tab) => (
                                    <li key={tab}>
                                        <button
                                            onClick={() => setActiveTab(tab)}
                                            className={activeTab === tab ? 'active' : ''}
                                        >
                                            {t(`TurnamentInfo.${tab}.header`)}
                                        </button>
                                        {activeTab === tab && <div className="button-list-line"/>}
                                    </li>
                                ))}
                                <li>
                                    <button onClick={logout}>
                                        {t('TurnamentInfo.logout')}
                                    </button>
                                </li>
                            </>
                        )}
                    </ul>
                </nav>
            </div>

            {showAuthModal && !isAuthorized && (
                <div className="auth-form">
                    <h3>{t('TurnamentInfo.authModal.title')}</h3>
                    <div className="auth-input">
                        <input 
                            type="password" 
                            value={password} 
                            onChange={(e) => setPassword(e.target.value)}
                            onKeyDown={handleKeyDown}
                            placeholder={t('TurnamentInfo.password.placeholder')}
                            autoFocus
                        />
                        <button onClick={handleCheckPassword}>
                            {t('TurnamentInfo.password.submit')}
                        </button>
                        {errorMessage && <div className="auth-error">{errorMessage}</div>}
                    </div>
                </div>
            )}

            <div className="content-with-guests">
                <img 
                    src="/images/background.png"
                    alt="Background" 
                    className="background-image"
                />
                <div className="specific-list">
                    {renderContent()}
                </div>
            </div>
        </section>
    );
};