import React, { useState, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { useQueryClient } from "react-query";
import { StatusesInterface } from "../../store/reducers/statuses-reducer";
import { ownerType } from "../../constants/types";
import { Search } from "../search/Search";
import { useTypedSelector } from "../../hooks/useTypedSelector";
import { isStatusFilterMatching } from "../../tools/isStatusFilterMatching";
import "./StatusesTable.css";

interface TableRowProps extends StatusesInterface {
    reference?: HTMLElement | null;
}

export const StatusesTable: React.FC = () => {
    const statuses = useQueryClient().getQueryData("statuses") as StatusesInterface[] | null;
    const { value } = useTypedSelector(store => store.searchReducer);
    const { t, i18n } = useTranslation();
    
    const [animatedClass, setAnimatedClass] = useState("");
    const [timeoutId, setTimeoutId] = useState<null | NodeJS.Timeout>(null);

    // Определяем текущий суффикс языка
    const lang = i18n.language.toUpperCase() as "RU" | "EN";
    const nameKey = `name${lang}` as keyof StatusesInterface;
    const descKey = `description${lang}` as keyof StatusesInterface;

    const shouldShowStatus = (status: StatusesInterface) => {
        return !!(status.owners && status.owners.length > 0 && !status.owners.includes("passive"));
    };

    // Основная логика фильтрации и сортировки
    const filteredAndSortedData = useMemo(() => {
        if (!statuses) return [];

        return statuses
            .filter(status => 
                shouldShowStatus(status) && 
                isStatusFilterMatching(value, status, i18n.language)
            )
            .sort((a, b) => {
                // Извлекаем названия и обрезаем лишние пробелы по краям (.trim())
                const nameA = String(a[nameKey] || "").trim();
                const nameB = String(b[nameKey] || "").trim();

                // localeCompare с чувствительностью 'base' игнорирует регистр
                return nameA.localeCompare(nameB, i18n.language, { 
                    sensitivity: 'base',
                    numeric: true 
                });
            });
    }, [statuses, value, i18n.language, nameKey]);

    const buttonsSections = [
        { owners: "sinner", header: t("StatusesTable.header.sinner") },
        { owners: "ego", header: t("StatusesTable.header.ego") },
        { owners: "sinner_story", header: t("StatusesTable.header.sinner_story") },
        { owners: "anomaly", header: t("StatusesTable.header.anomaly") },
        { owners: "md_gift", header: t("StatusesTable.header.md_gift") },
        { owners: "none", header: t("StatusesTable.header.none") },
    ];

    const handleScroll = (statusId: string, index: number) => {
        const status = filteredAndSortedData.find((s) => s.id === statusId) as TableRowProps;
        if (status?.reference) {
            status.reference.scrollIntoView({ behavior: 'smooth', block: 'center' });
            
            if (timeoutId) clearTimeout(timeoutId);
            setAnimatedClass(statusId);
            const newId = setTimeout(() => setAnimatedClass(""), 1000 + index * 5);
            setTimeoutId(newId);
        }
    };

    return (
        <>
            {buttonsSections.map((section, sIdx) => (
                <section key={sIdx} className="statuses-section">
                    <h2>{section.header}</h2>
                    <article className="statuses-buttons">
                        {filteredAndSortedData.map((status, index) => {
                            if (status.owners?.includes(section.owners as ownerType)) {
                                return (
                                    <button key={status.id} onClick={() => handleScroll(status.id, index)}>
                                        <div className="status-tooltip">{String(status[nameKey])}</div>
                                        <img 
                                            src={`${process.env.PUBLIC_URL}/images/tags/${status.id}.webp`} 
                                            alt={status.id} 
                                        />
                                    </button>
                                );
                            }
                            return null;
                        })}
                    </article>
                </section>
            ))}

            <section className="statuses-section">
                <Search />
            </section>

            <table className="statuses-table">
                <thead>
                    <tr>
                        <th className="statuses-table-th-image">{t("StatusesTable.status")}</th>
                        <th className="statuses-table-th-name">{t("StatusesTable.name")}</th>
                        <th className="statuses-table-th-description">{t("StatusesTable.description")}</th>
                    </tr>
                </thead>
                <tbody>
                    {filteredAndSortedData.map((status) => {
                        const name = String(status[nameKey] || "");
                        const description = String(status[descKey] || "");
                        const formattedHTML = description.replaceAll('%', '<span class="perCent-special-font">%</span>');

                        return (
                            <tr 
                                key={status.id} 
                                className={status.id === animatedClass ? "statuses-table-tr--active" : ""} 
                                ref={(el) => ((status as TableRowProps).reference = el)}
                            >
                                <td className="statuses-table-th-image">
                                    <img src={`${process.env.PUBLIC_URL}/images/tags/${status.id}.webp`} alt={status.id} />
                                </td>
                                <td className="statuses-table-th-name">{name}</td>
                                <td 
                                    className="statuses-table-th-description" 
                                    dangerouslySetInnerHTML={{ __html: formattedHTML }}
                                />
                            </tr>
                        );
                    })}
                </tbody>
            </table>
        </>
    );
};