import { useQuery, QueryClient } from "react-query";
import { SUPABASE_URL, SUPABASE_ANON_KEY } from "../utils/supabaseClient";

const CACHE_KEY = 'ChanLog_cache';
const CACHE_TIME = 15 * 60 * 1000; 

// 1. Управляем кэшем (оставляем вашу логику)
const getDataFromCache = () => {
  if (typeof window === 'undefined') return null;
  const cachedData = localStorage.getItem(CACHE_KEY);
  if (cachedData) {
    const { data, timestamp } = JSON.parse(cachedData);
    if (Date.now() - timestamp < CACHE_TIME) {
      return data;
    }
  }
  return null;
};

const setDataToCache = (data: any) => {
  const cacheData = {
    data,
    timestamp: Date.now(),
  };
  localStorage.setItem(CACHE_KEY, JSON.stringify(cacheData));
};

const useFetchChanLogAction = async () => {
  const cached = getDataFromCache();
  if (cached) return cached;

  // Формируем URL с ключом внутри (Query Parameter)
  const endpoint = '/rest/v1/changelog?select=*';
  const url = `${SUPABASE_URL}${endpoint}&apikey=${SUPABASE_ANON_KEY}`;

  const response = await fetch(url, {
    method: 'GET',
    headers: {
      'Content-Type': 'application/json',
      // Оставляем только самое необходимое
    }
  });

  if (!response.ok) {
    throw new Error(`Ошибка: ${response.status}`);
  }

  const data = await response.json();
  setDataToCache(data);
  return data;
};

// 3. Основной хук
export const useFetchChanLog = () => {
  return useQuery("changelog", useFetchChanLogAction, {
    staleTime: CACHE_TIME,
    cacheTime: Infinity,
    refetchOnWindowFocus: false,
    retry: 5,
    retryDelay: (attempt) =>
        Math.min(attempt > 1 ? 2 ** attempt * 1000 : 1000, 30 * 1000),
    onError: (error) => {
      console.error("Error fetching ChanLog from Supabase:", error);
    },
  });
};

// 4. Client для React Query
export const createQueryClient = () => {
  const queryClient = new QueryClient({
    defaultOptions: {
      queries: {
        staleTime: CACHE_TIME,
        cacheTime: Infinity,
      },
    },
  });

  if (typeof window !== 'undefined') {
    const cachedData = getDataFromCache();
    if (cachedData) {
      queryClient.setQueryData("changelog", cachedData);
    }
  }

  return queryClient;
}