import React from 'react';
import "./TooltipMobile.css"
import { SkillCoinDescription } from "../guides/text-formatter/SkillCoinDescription";

interface ITooltipMobileProps {
    image?: React.ReactNode,
    header?: string
    text: string,
}

export const TooltipMobile: React.FC<ITooltipMobileProps> = ({ image, text, header }) => {
    return (
        <div className='TooltipMobile'>
            {
                (!!header || !!image) && <>
                    <span className='TooltipMobile-header'>
                        {!!header ? header : ""}
                        {!!image ? image : <></>}
                    </span>
                    <hr />
                </>
            }
            {/* Используем наш парсер для вывода описания внутри тултипа */}
            <span className='TooltipMobile-info'>
                <SkillCoinDescription description={text} />
            </span>
        </div>
    );
};