import React, { useEffect, useRef } from "react";
import { useTranslation } from "react-i18next";
import { useQueryClient } from "react-query";
import { useDispatch } from "react-redux";
import { useTypedSelector } from "../../hooks/useTypedSelector";
import { IdentityInterface } from "../../store/reducers/ids-reducer";
import { searchChangeTargetRefAction } from "../../store/reducers/search-reducer";
import { isFilterMatching } from "../../tools/isFilterMatching";
import { ItemEntity } from "../item-entity/ItemEntity";
import { ListSinnerBar } from "../list-sinner-bar/ListSinnerBar";
import { StatusesInterface } from "../../store/reducers/statuses-reducer";
import "./ListIds.css";

export const ListIds:React.FC = () => {
    const containerRef = useRef(null);
    const dispatch = useDispatch();
    const ids = useQueryClient().getQueryData("identities") as IdentityInterface[]|null;
    const statuses = useQueryClient().getQueryData('statuses') as StatusesInterface[];
    const filterState = useTypedSelector(state => state.filterReducer);
    const searchState = useTypedSelector(state => state.searchReducer);
    const {t,i18n} = useTranslation();

    useEffect(()=>{
        searchChangeTargetRefAction(dispatch,containerRef)
    },[])
    
    const idMap: {
        [key:string]:React.ReactNode[]
    } = {
        "new":[],
        "yi sang":[],
        "faust":[],
        "don quixote":[],
        "ryoshu":[],
        "mersault":[],
        "hong lu":[],
        "heathcliff":[],
        "ishmael":[],
        "rodion":[],
        "sinclair":[],
        "outis":[],
        "gregor":[],
    };

    let totalCount = 0;

    // Функция для проверки статусов через statusUnik
    const checkStatusUnik = (entity: IdentityInterface, activeTags: string[]): boolean => {
        if (!entity.statusUnik) return true; // Если нет statusUnik - пропускаем
        
        const [addPart, removePart] = entity.statusUnik.split('|').map(part => part.trim());
        const statusesToRemove = removePart ? removePart.split('#').filter(s => s.trim()).map(s => s.trim().toLowerCase()) : [];

        // Проверяем, есть ли среди активных тегов те, которые нужно удалить
        for (const activeTag of activeTags) {
            if (statusesToRemove.includes(activeTag.toLowerCase())) {
                console.log(`🚫 [${entity.imgUrl}] Исключен по statusUnik: тег "${activeTag}" в списке удаления`);
                return false;
            }
        }

        return true;
    };

    if (ids) {
        // Сортировка по дате (от новых к старым)
        const sortedIds = [...ids].sort((a, b) => {
            const d1 = new Date(a.releaseDate).getTime();
            const d2 = new Date(b.releaseDate).getTime();
            return d2 - d1;
        });

        const activeTags = Object.keys(filterState.types.tags).filter(key => filterState.types.tags[key] === true);

        // Идем по порядку от 0 (где теперь самые новые)
        for (let i = 0; i < sortedIds.length; i++) {
            const currentID = sortedIds[i];
            const { isNew, imgUrl, sinner } = currentID;

            // Проверки (statusUnik и обычная фильтрация)
            if (!checkStatusUnik(currentID, activeTags)) continue;
            if (!isFilterMatching(filterState, searchState, currentID, i18n.language, statuses)) continue;

            // Теперь push добавит элементы в массивы idMap по порядку даты
            if (!!(+isNew)) {
                idMap.new.push(<ItemEntity animationDelay={500} entity={currentID} key={`${imgUrl}-new`}/>);
            }
            if (sinner in idMap) {
                idMap[sinner].push(<ItemEntity animationDelay={500} entity={currentID} key={imgUrl}/>);
            }
            totalCount++;
        }
    }

    console.log('\n=== ИТОГИ ===');
    console.log(`Всего прошло: ${totalCount} личностей`);

    return (
        <section ref={containerRef} className={"list-ids"}>
        <span className={"list-ids-span"}>{`${t("ListIds.header")} (${totalCount})`}</span>
        {
           totalCount !== 0 ? <>
                {
                    Object.entries(idMap).map((entry)=>{
                        const [key,value] = entry;
                        if(!value.length) return null;
                        return <ListSinnerBar key={key} sinner={key} data={value}/> 
                    })
                }
            </>
            : <p>
                {t("ListIds.empty")}
            </p>
        }
        </section>
    )
}