import React, { useState, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { useQueryClient } from 'react-query';
import { useDispatch } from 'react-redux';
import { IdentityInterface } from '../../../store/reducers/ids-reducer';
import { setMobileModalTrigger } from '../../../store/reducers/mobile-modal-reducer';
import { StatusesInterface } from '../../../store/reducers/statuses-reducer';
import { getStatusesEntityList } from '../../../tools/getStatusesEntityList';
import { TooltipMobile } from '../../tooltip-mobile/TooltipMobile';
import "./EntityFullInfoIdentity.css"
import { useTypedSelector } from '../../../hooks/useTypedSelector';

interface IEntityFullInfoProps {
    identity: IdentityInterface;
    maxLvlIdentity: number;
    statusUnik?: string; // параметр необязательный, если его нет - логика без фильтров
}

const resMap: { [key: string]: string } = {
    'ineff': '[x0.5]',
    'normal': '[x1]',
    'fatal': '[x2]'
}

export const EntityFullInfoIdentity: React.FC<IEntityFullInfoProps> = ({ identity, maxLvlIdentity, statusUnik }) => {
    const { imgUrl, idTier, season, hp, hpStun, speed: speeds, defense, slash, pierce, blunt, rarity, sinner, releaseDate } = identity;
    const statuses = useQueryClient().getQueryData('statuses') as StatusesInterface[];
    const rarityStyled = rarity.replaceAll("O", "Ø");
    const { t, i18n } = useTranslation();
    const dispatch = useDispatch();
    
    const { selectedUptie } = useTypedSelector(s => s.uptieReducer);

    const descriptionCoinKey = `descriptionCoin${i18n.language.toUpperCase()}${selectedUptie}` as keyof typeof identity;
    const descriptionCoin = identity[descriptionCoinKey] as string || '';

    const lang = i18n.language.toUpperCase();

    // Получаем пассивные описания (Passive 1 и Passive 2)
    const descriptionPassive1 = identity[`descriptionPassive1${lang}` as keyof typeof identity] as string || '';
    const descriptionPassive2 = identity[`descriptionPassive2${lang}` as keyof typeof identity] as string || '';

    // Теперь передаем в утилиту все доступные текстовые поля
    const status = useMemo(() => {
        return getStatusesEntityList([
            descriptionCoin, 
            descriptionPassive1, 
            descriptionPassive2
        ]);
    }, [descriptionCoin, descriptionPassive1, descriptionPassive2]);

    const [imgID, setImgID] = useState('2');
    const isSwitched = imgID === '2';

    function updateStatusWithFuseStatuses(
        allStatuses: StatusesInterface[],
        status: { [key: string]: number }
    ): { [key: string]: number } {
        const updatedStatus = { ...status };
        for (const id of Object.keys(status)) {
            const foundStatus = allStatuses.find(s => s.id === id);
            if (foundStatus && foundStatus.fuse_statuses) {
                const fuseId = foundStatus.fuse_statuses;
                if (!(fuseId in updatedStatus)) {
                    updatedStatus[fuseId] = 0;
                }
            }
        }
        return updatedStatus;
    }

    const fuseStatuses = useMemo(() => {
            return updateStatusWithFuseStatuses(statuses, status);
        }, [statuses, status, selectedUptie]);

        const filteredStatusKeys = useMemo(() => {
        if (!fuseStatuses) return [];

        console.log('fuseStatuses:', fuseStatuses);
        console.log('statusUnik:', statusUnik);

        if (!statusUnik) {
            const filtered = Object.keys(fuseStatuses).filter(s => fuseStatuses[s] > 0);
            console.log('No statusUnik, filtered:', filtered);
            return filtered;
        }

        const [addPart, removePart] = statusUnik.split('|').map(part => part.trim());
        const statusesToAdd = addPart ? addPart.split('#').filter(s => s.trim()).map(s => s.trim().toLowerCase()) : [];
        const statusesToRemove = removePart ? removePart.split('#').filter(s => s.trim()).map(s => s.trim().toLowerCase()) : [];

        console.log('statusesToAdd:', statusesToAdd);
        console.log('statusesToRemove:', statusesToRemove);

        // Фильтрация - убираем статусы для удаления и оставляем > 0
        let filtered = Object.keys(fuseStatuses).filter(s => {
            const lower = s.toLowerCase();
            const keep = !statusesToRemove.includes(lower) && fuseStatuses[s] > 0;
            if (!keep) {
                console.log(`Removing status: ${s}`);
            }
            return keep;
        });

        // Добавляем недостающие из statusesToAdd
        statusesToAdd.forEach(statusToAdd => {
            // Ищем полное название статуса в базе статусов
            const foundStatus = statuses.find(st => 
                st.id.toLowerCase() === statusToAdd
            );
            
            if (foundStatus) {
                const fullStatusId = foundStatus.id;
                if (!filtered.includes(fullStatusId)) {
                    console.log(`Adding status: ${fullStatusId}`);
                    filtered.push(fullStatusId);
                }
            } else {
                // Если не нашли в базе, добавляем как есть (на случай если это новый статус)
                if (!filtered.includes(statusToAdd)) {
                    console.log(`Adding status (not found in DB): ${statusToAdd}`);
                    filtered.push(statusToAdd);
                }
            }
        });

        console.log('Result filteredStatusKeys:', filtered);
        return filtered;
    }, [fuseStatuses, statusUnik, statuses]);

    const speed = useMemo(() => {
        if (Array.isArray(speeds)) {
            return speeds[selectedUptie - 1] || speeds[0];
        }
        return speeds;
    }, [speeds, selectedUptie]);

    const getImagePath = () => {
        let basePath = `${process.env.PUBLIC_URL}/images/identities-profiles/${imgUrl}`;
        if (imgID !== '2') {
            return `${basePath}.${imgID}_profile.webp`;
        }
        if ([1, 2].includes(selectedUptie)) {
            return `${basePath}.1_profile.webp`;
        } else if ([3, 4].includes(selectedUptie)) {
            return `${basePath}.2_profile.webp`;
        }
        return `${basePath}_profile.webp`;
    };

    const defLevelValue = maxLvlIdentity - (-defense);

    function excelToDate(excelDate: number) {
        const excelStartDate = new Date(1899, 11, 30);
        const millisecondsPerDay = 24 * 60 * 60 * 1000;
        return new Date(excelStartDate.getTime() + excelDate * millisecondsPerDay);
    }

    const formateDate = (date: number) => {
        const newDate = excelToDate(date);
        const month = `${newDate.getMonth() + 1}`;
        const day = `${newDate.getDate()}`;
        return `${day.length === 1 ? `0${day}` : day}.${month.length === 1 ? `0${month}` : month}.${newDate.getFullYear()}`
    }

    const toggleImgID = () => setImgID(prevID => (prevID === '1' ? '2' : '1'));

    const shouldShowSwapButton = !(
        imgUrl.startsWith('id_') &&
        parseInt(imgUrl.replace('id_', ''), 10) >= 1 &&
        parseInt(imgUrl.replace('id_', ''), 10) <= 12
    );

    return (
        <section className={'entityFullInfo-entity'}>
            <article className={"entityFullInfo-img"}>
                <div className="entityFullInfo-rarity">{rarityStyled}</div>
                <img className="entityFullInfo-sinner" src={`${process.env.PUBLIC_URL}/images/sinners-icons/${sinner}.webp`} alt={`${sinner}`} />
                <div className={"shadow"}>
                    <img src={getImagePath()} alt={`${imgUrl}`} />
                </div>
                {shouldShowSwapButton && (
                    <button onClick={toggleImgID} className="image-swap-button">
                        {t(isSwitched ? "EntityFullInfoIdentity.switchImage2" : "EntityFullInfoIdentity.switchImage1")}
                    </button>
                )}
                <div className={`entityFullInfo-tier entityFullInfo-tier-${idTier}`}>
                    {idTier}
                </div>
            </article>
            <div className={'entityFullInfo-stats-container'}>
                <article className={"entityFullInfo-stats"}>
                    <h2>{t("EntityFullInfoIdentity.info")}</h2>
                    {!season[1] ?
                        <div className={`entityFullInfo-season entityFullInfo-season-${season[0][0] === 'w' ? 'w' : season[0].replace(/^i-/, 's-')}`}>
                            {t(`EntityFullInfoIdentity.season.${season}`)}
                        </div> :
                        <div className={`entityFullInfo-season entityFullInfo-season-${season[1][0] === 'w' ? 'w' : season[0].replace(/^i-/, 's-')}`}>
                            {t(`EntityFullInfoIdentity.season.${season[0]}`)} [{t(`EntityFullInfoIdentity.season.${season[1]}`)}]
                        </div>
                    }
                    <div className={"entityFullInfo-release"}>
                        {t('EntityFullInfoIdentity.release')}
                        &nbsp;
                        <span className="date">{formateDate(releaseDate)}</span>
                    </div>
                </article>

                {fuseStatuses && (
                    <article className={"entityFullInfo-stats"}>
                        <h2>{t("EntityFullInfoIdentity.statuses")}</h2>
                        <ul className='statuses-list'>
                            {
                                filteredStatusKeys.map((s, index) => {
                                    const status = statuses.find(st => st.id === s);
                                    if (!status) return null;
                                    const descriptionKey = `description${i18n.language.toUpperCase()}` as keyof typeof status;
                                    const description = status?.[descriptionKey] as string || '';
                                    const nameKey = `name${i18n.language.toUpperCase()}` as keyof typeof status;
                                    const name = status?.[nameKey] as string || '';
                                    const imgHTML = <img src={`${process.env.PUBLIC_URL}/images/tags/${s}.webp`} alt={`${s}`} />;
                                    const mobileStatusHTML = <TooltipMobile text={description} header={name} image={imgHTML} />;
                                    return (
                                        <li key={index} onClick={() => setMobileModalTrigger(dispatch, mobileStatusHTML)} className='tooltip-container '>
                                            {imgHTML}
                                            <span className='entityFullInfo-tooltip '>
                                                {t("SkillCoinDescription.clickToSeeDescription")}
                                            </span>
                                        </li>
                                    );
                                })
                            }
                        </ul>
                    </article>
                )}

                <article className={"entityFullInfo-stats"}>
                    <h2>{t("EntityFullInfoIdentity.stats")}</h2>
                    <ul>
                        <li>
                            <img src={`${process.env.PUBLIC_URL}/images/general/hp.webp`} alt={`${imgUrl}`} />
                            {hp}
                        </li>
                        <li>
                            <img src={`${process.env.PUBLIC_URL}/images/general/speed.webp`} alt={`${imgUrl}`} />
                            {speed}
                        </li>
                        <li>
                            <img src={`${process.env.PUBLIC_URL}/images/general/defense1.webp`} alt={`${imgUrl}`} />
                            {defLevelValue}
                        </li>
                    </ul>
                </article>

                <article className={"entityFullInfo-stats"}>
                    <h2>{t("EntityFullInfoIdentity.res")}</h2>
                    <ul>
                        <li className={`resistance--${blunt}`}>
                            <img src={`${process.env.PUBLIC_URL}/images/general/blunt.webp`} alt={`${imgUrl}`} />
                            {resMap[blunt]}
                        </li>
                        <li className={`resistance--${pierce}`}>
                            <img src={`${process.env.PUBLIC_URL}/images/general/pierce.webp`} alt={`${imgUrl}`} />
                            {resMap[pierce]}
                        </li>
                        <li className={`resistance--${slash}`}>
                            <img src={`${process.env.PUBLIC_URL}/images/general/slash.webp`} alt={`${imgUrl}`} />
                            {resMap[slash]}
                        </li>
                    </ul>
                </article>

                <article className={"entityFullInfo-stats"}>
                    <h2>{t("EntityFullInfoIdentity.stagger")}</h2>
                    <ul className='staggers'>
                        {hpStun.map((e, index) => (
                            <li key={index}>
                                <span>
                                    {(hp * e / 100).toFixed()} ({e}
                                    <span className='perCent-special-font'>%</span>)
                                </span>
                            </li>
                        ))}
                    </ul>
                </article>
            </div>
        </section>
    );
};
