export const getStatusesEntityList = (strsArr: string[] | undefined) => {
    const result: {
        [key: string]: number;
    } = {};
    
    // Проверяем, что strsArr существует и является массивом
    if (!strsArr || !Array.isArray(strsArr)) {
        return result;
    }
    
    strsArr.forEach(l => {
        // Проверяем, что элемент существует и является строкой
        if (!l || typeof l !== 'string') {
            return;
        }
        
        const current = l.split("#");
        for (let i = 1; i < current.length; i += 2) {
            const currTag = current[i];
            if (!currTag) continue;
            if (!(currTag in result)) {
                result[currTag] = 1;
            } else {
                result[currTag] += 1;
            }
        }
    });
    
    return result;
};