import { useRef, useCallback, useEffect } from 'react';
import { useTranslation } from "react-i18next";
import { LanguageDisclaimer } from "../language-disclaimer/LanguageDisclaimer";
import { EntitySection } from "./EntitySection/EntitySection";
import { EventsSection } from "./EventsSection/EventsSection";
import { NewsSection } from "./NewsSection/NewsSection";
import "./MainInfo.css";
import { useState } from 'react';
import { NavigationSection } from "./NavigationSection/NavigationSection";
import { OfficialLinksSection } from "./OfficialLinksSection/OfficialLinksSection";
import { ToDoSection } from "./ToDoSection/ToDoSection";

// Конфигурация аудио (сумма chance должна быть 1.0)
const AUDIO_CONFIG = [
    {
        file: '/kwai.mp3',
        segments: [
            { start: -1, end: 1, chance: 0.1 },
            { start: 10, end: 12, chance: 0.3 },
            { start: 12, end: 14, chance: 0.4 },
            { start: 20, end: 22, chance: 0.2 }
        ],
        chance: 0.92 
    },
    {
        file: '/love.mp3',
        playFull: true,
        chance: 0.01 
    },
    {
        file: '/man.mp3',
        playFull: true,
        chance: 0.01 
    },
    {
        file: '/goodbye.mp3',
        playFull: true,
        chance: 0.01 
    },
    {
        file: '/hello.mp3',
        playFull: true,
        chance: 0.01 
    },
    {
        file: '/beach-volleyball.mp3',
        playFull: true,
        chance: 0.01 
    },
    {
        file: '/sir-squirrel.mp3',
        playFull: true,
        chance: 0.01 
    },
    {
        file: '/limbus-companyyyy.mp3',
        playFull: true,
        chance: 0.01 
    },
    {
        file: '/danteh.mp3',
        playFull: true,
        chance: 0.01 
    }
];

// Проверка суммы шансов
const totalChance = AUDIO_CONFIG.reduce((sum, option) => sum + option.chance, 0);
if (Math.abs(totalChance - 1) > 0.0001) {
    console.error(`Audio config error! Total chance must be 1.0, current sum: ${totalChance}`);
}

function getRandomAudioOption() {
    const random = Math.random();
    let cumulativeChance = 0;

    for (const option of AUDIO_CONFIG) {
        cumulativeChance += option.chance;
        if (random <= cumulativeChance) {
            return option;
        }
    }

    return AUDIO_CONFIG[0]; // fallback
}

function getRandomSegmentWithChance(segments: {start: number, end: number, chance: number}[]) {
    const random = Math.random();
    let cumulativeChance = 0;

    for (const segment of segments) {
        cumulativeChance += segment.chance;
        if (random <= cumulativeChance) {
            return segment;
        }
    }

    return segments[0]; // fallback
}
const ClearCacheButton = () => {
  const [isHovered, setIsHovered] = useState(false);

  const handleClearCache = () => {
    // Очистка localStorage
    localStorage.clear();
    
    // Очистка sessionStorage
    sessionStorage.clear();
    
    // Очистка кеша (принудительная перезагрузка с параметром для избежания кеширования)
    window.location.href = window.location.href + '?nocache=' + new Date().getTime();
  };

  return (
    <div
      style={{
        position: 'fixed',
        top: '10px',
        right: '10px',
        width: isHovered ? '80px' : '30px',
        height: '30px',
        backgroundColor: 'rgba(19, 19, 25, 0.8)',
        borderRadius: '5px',
        display: 'flex',
        border: '0.2px solid rgba(255, 255, 255, 1)',
        alignItems: 'center',
        justifyContent: 'center',
        cursor: 'pointer',
        transition: 'width 0.3s ease',
        zIndex: 10000,
        overflow: 'hidden',
        boxShadow: '0 2px 5px rgba(0,0,0,0.3)'
      }}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onClick={handleClearCache}
      title="Clear cache and refresh"
    >
      {isHovered && (
        <span style={{
          color: 'white',
          fontSize: '14px',
          fontWeight: 'bold',
          whiteSpace: 'nowrap'
        }}>
          clear all cashies
        </span>
      )}
      {!isHovered && (
        <span style={{
          color: 'white',
          fontSize: '16px',
          fontWeight: 'bold'
        }}>
          ×
        </span>
      )}
    </div>
  );
};
export const MainInfo: React.FC = () => {
    const { t, i18n } = useTranslation();
    const jabImageRef = useRef<HTMLImageElement>(null);
    
    // Реф для управления аудио
    const audioContextRef = useRef<{
        audio: HTMLAudioElement | null;
        stopTimer: NodeJS.Timeout | null;
        isPlaying: boolean;
    }>({
        audio: null,
        stopTimer: null,
        isPlaying: false
    });

    // Очистка при размонтировании компонента
    useEffect(() => {
        return () => {
            const ctx = audioContextRef.current;
            if (ctx.stopTimer) clearTimeout(ctx.stopTimer);
            if (ctx.audio) {
                ctx.audio.pause();
                ctx.audio.currentTime = 0;
                ctx.audio.onended = null;
                ctx.audio.onerror = null;
            }
        };
    }, []);

    const playRandomAudio = useCallback(() => {
        const ctx = audioContextRef.current;
        
        if (ctx.isPlaying) {
            console.log("Audio is already playing, skipping...");
            return;
        }
        
        const audioOption = getRandomAudioOption();
        console.log("Playing audio:", audioOption.file);
        
        // Очистка предыдущего состояния
        if (ctx.audio) {
            ctx.audio.pause();
            ctx.audio.currentTime = 0;
        }
        if (ctx.stopTimer) {
            clearTimeout(ctx.stopTimer);
            ctx.stopTimer = null;
        }
        
        // Создание нового аудио элемента
        const audio = new Audio(audioOption.file);
        ctx.audio = audio;
        
        const cleanupAudio = () => {
            if (ctx.audio === audio) {
                ctx.audio.pause();
                ctx.audio.currentTime = 0;
                ctx.audio = null;
            }
            if (ctx.stopTimer) {
                clearTimeout(ctx.stopTimer);
                ctx.stopTimer = null;
            }
            ctx.isPlaying = false;
        };
        
        audio.onerror = () => {
            console.error("Audio error:", audioOption.file);
            cleanupAudio();
        };
        
        if (audioOption.playFull) {
            if (audioOption.file === '/goodbye.mp3') {
                audio.onended = () => {
                    console.log("Goodbye audio finished - closing site");
                    // Не вызываем cleanupAudio() здесь - просто устанавливаем флаг
                    ctx.isPlaying = false;
                    
                    setTimeout(() => {
                        window.location.href = 'https://www.google.com';
                    }, 1000);
                };
            } else {
                audio.onended = () => {
                    console.log("Audio finished:", audioOption.file);
                    cleanupAudio();
                };
            }
        } else {
            // Проверяем существование segments
            if (!audioOption.segments || audioOption.segments.length === 0) {
                console.error("No segments defined for:", audioOption.file);
                return;
            }
            
            const segment = getRandomSegmentWithChance(audioOption.segments);
            console.log("Playing segment:", segment);
            
            audio.currentTime = segment.start;
            const duration = (segment.end - segment.start) * 1000;
            
            ctx.stopTimer = setTimeout(() => {
                console.log("Segment finished:", audioOption.file);
                cleanupAudio();
            }, duration);
        }
        
        // Устанавливаем флаг и воспроизводим
        ctx.isPlaying = true;
        audio.play().catch(e => {
            console.error("Play failed:", e);
            cleanupAudio();
        });
        
    }, []);

    const handleJabClick = useCallback((e: React.MouseEvent<HTMLImageElement>) => {
        e.preventDefault();
        e.stopPropagation();
        playRandomAudio();
        
        if (jabImageRef.current) {
            jabImageRef.current.classList.add('jab-pressed');
            setTimeout(() => {
                jabImageRef.current?.classList.remove('jab-pressed');
            }, 300);
        }
    }, [playRandomAudio]);

    // Dynamic image paths
    const teaserImagePath = i18n.language === 'ru' ? "/images/reklamaru.webp" : "/images/reklamaen.webp";
    const teaserImagePath2 = i18n.language === 'ru' ? "/images/disru.webp" : "/images/disen.webp";
    const teaserImagePath3 = i18n.language === 'ru' ? "/images/jab.png" : "/images/jab.png";
    const teaserImagePath4 = i18n.language === 'ru' ? "/images/battle_toad.png" : "/images/battle_toad.png";

    return (
        
        <section className="main-info">
            <ClearCacheButton />
            <header className="main-info-header-main">
                <h1 onClick={() => window.open("https://gll-fun.com/ru/test/description", "_blank")} style={{ cursor: "pointer" }}>
                    Great <span>Limbus</span> Library
                </h1>
                <p className="main-info-header-description">
                    {t(`MainInfo.headerDescription1`)}<br /><br />
                </p>
                <LanguageDisclaimer />
            </header>
            <div className="rek-image-container">
                <div className="animate-fade-in"><img 
                    src={teaserImagePath2} 
                    className="reklama-image2"
                    onClick={() => window.location.href = "https://discord.gg/BGpmmqknWE"}
                /></div>
                <div className="jab-image-container animate-fade-in" onClick={handleJabClick}>
                    <img 
                        ref={jabImageRef}
                        src={teaserImagePath3} 
                        className="jab-image"
                    />
                </div>
                
                <div className="animate-fade-in"><img 
                    src={teaserImagePath} 
                    className="reklama-image"
                    onClick={() => window.location.href = "https://boosty.to/gll-fun"}
                /></div>
            </div>
            <section className="main-info-left">
                <EntitySection />
                <NavigationSection />
                <ToDoSection />
                <OfficialLinksSection />
            </section>
            <section className="main-info-right">
                <NewsSection />
                
                <EventsSection />
            </section>
        </section>
    );
};