import React from "react";
import { useTranslation } from "react-i18next";
import { TurnamentInfo } from "../components/turnament/TurnamentInfo";
import { CommonPageLayout } from "./CommonPageLayout";
import { SEOHelmet } from "./SEOHelmet";
import { LoadingPageWrapper } from "./LoadingPageWrapper";
import Analytics from "../components/Analytics";
import Sweepers from "../components/Sweepers";

export const TurnamentPage: React.FC = () => {
    const { t } = useTranslation();
    
    return (
        
            <CommonPageLayout>
                <Sweepers/>
                <Analytics />
                <LoadingPageWrapper queryKeys={["bingo", "turnamnetgrid"]}><TurnamentInfo/></LoadingPageWrapper>
                <SEOHelmet titleText={t("TurnamentPage.title") + " | Great Limbus Library"} descriptionText=""/>
                
            </CommonPageLayout>
    );
}