import React, { useEffect } from "react";
import "./uptie-component.css";
import { UptieState, uptieSwitchAction } from "../../../store/reducers/uptie-reducer";
import { useDispatch } from "react-redux";
import { useLocation } from "react-router-dom"; // или useParams, в зависимости от маршрутизации

interface UptieComponentProps {
  value: number;
  setValue: React.Dispatch<React.SetStateAction<number>>;
}

export const UptieComponent: React.FC<UptieComponentProps> = ({ value, setValue }) => {
  const dispatch = useDispatch();
  const location = useLocation(); // отслеживаем путь
  // Если используете react-router с параметрами, можно также использовать useParams:
  // const { id } = useParams<{ id: string }>();
  
  const min = 1;
  const max = 4;
  const steps = [1, 2, 3, 4];
  const steps_values = ["I", "II", "III", "IV"];
  const steps_offsets_X = [70, 60, -40, -70];

  // Эффект для сброса значения при переходе на страницу identities/id_xxx
  useEffect(() => {
    // Проверяем, что путь соответствует паттерну /identities/id_xxx
    const identityPathRegex = /\/identities\/id_/;
    if (identityPathRegex.test(location.pathname)) {
      setValue(4); // Устанавливаем значение 4
      const typed_value = 4 as UptieState["selectedUptie"];
      uptieSwitchAction(dispatch, typed_value); // Обновляем стор, если нужно
    }
  }, [location.pathname, dispatch, setValue]); // Зависимость от пути

  const handleValueSwitch = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newValue = Number(e.target.value);
    if (steps.includes(newValue)) {
      const typed_value = newValue as UptieState["selectedUptie"];
      setValue(typed_value);
      uptieSwitchAction(dispatch, typed_value);
    }
  };

  return (
    <div className="uptie-container">
      <span className="uptie-value-current">
        <span className="uptie-uptie-text">Uptie</span>
        {steps_values[value - 1]}
      </span>

      <div className="uptie-slider-container">
        <input
          className="uptie-range"
          type="range"
          min={min}
          max={max}
          step="1"
          value={value}
          onChange={handleValueSwitch}
          style={{ backgroundSize: `${((value - min) / (max - min)) * 100}% 100%` }}
        />
        {steps.map((step) => (
          <div
            key={step}
            style={{ left: `${((step - min) / (max - min)) * 100}%` }}
            className="slider-splitmark"
          />
        ))}

        <div className="slider-labels">
          {steps.map((step, index) => (
            <div key={step} className="slider-mark" style={{ left: `${((step - min) / (max - min)) * 100}%` }}>
              <span className={`slider-text ${value === index + 1 ? "slider-text--current" : ""}`} style={{
                transform: `translateX(${steps_offsets_X[index]}%)`
              }}>
                {steps_values[index]}
              </span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};