import { useQuery, QueryClient } from "react-query";
import { SUPABASE_URL, SUPABASE_ANON_KEY } from "../utils/supabaseClient";

// 1. Константы кэширования
const CACHE_KEY = 'guides_supabase_cache';
const CACHE_TIME = 15 * 60 * 1000; // 35 минут

// 2. Утилиты кэша
const getDataFromCache = () => {
  if (typeof window === 'undefined') return null;
  const cachedData = localStorage.getItem(CACHE_KEY);
  if (cachedData) {
    const { data, timestamp } = JSON.parse(cachedData);
    if (Date.now() - timestamp < CACHE_TIME) {
      return data;
    }
  }
  return null;
};

const setDataToCache = (data: any) => {
  const cacheData = {
    data,
    timestamp: Date.now(),
  };
  localStorage.setItem(CACHE_KEY, JSON.stringify(cacheData));
};

// 3. Логика запроса к Supabase
const useFetchGuidesAction = async () => {
  const cached = getDataFromCache();
  if (cached) return cached;

  // Используем вашу новую таблицу (убедитесь, что имя совпадает с тем, что в DBeaver)
  // Добавляем order=ids.asc, чтобы данные всегда шли в правильном порядке
  const endpoint = '/rest/v1/guides?select=*&order=ids.asc';
  const url = `${SUPABASE_URL}${endpoint}&apikey=${SUPABASE_ANON_KEY}`;

  const response = await fetch(url, {
    method: 'GET',
    headers: {
      'Content-Type': 'application/json',
      'Prefer': 'return=representation' 
    }
  });

  if (!response.ok) {
    throw new Error(`Ошибка Supabase: ${response.status}`);
  }

  const data = await response.json();
  setDataToCache(data);
  return data;
};

// 4. Основной хук для компонентов
export const useFetchGuides = () => {
  return useQuery("guides", useFetchGuidesAction, {
    staleTime: CACHE_TIME,
    cacheTime: Infinity,
    refetchOnWindowFocus: false,
    retry: 8,
    retryDelay: (attempt) =>
      Math.min(attempt > 1 ? 2 ** attempt * 1000 : 1000, 30 * 1000),
    onError: (error) => {
      console.error("Error fetching guides from Supabase:", error);
    },
  });
};

// 5. Создание клиента (для использования в App.tsx / _app.tsx)
export const createQueryClient = () => {
  const queryClient = new QueryClient({
    defaultOptions: {
      queries: {
        staleTime: CACHE_TIME,
        cacheTime: Infinity,
      },
    },
  });

  if (typeof window !== 'undefined') {
    const cachedData = getDataFromCache();
    if (cachedData) {
      queryClient.setQueryData("guides", cachedData);
    }
  }

  return queryClient;
};